import type React from 'react';
import { isFunction } from './assert';

/**
 * refObject 延迟获取元素方法
 */
export type RefThunkElement<T> = React.RefObject<T> | React.MutableRefObject<T | null>;

/**
 * callback 延迟获取元素方法
 */
export type CallbackThunkElement<T> = () => T | null;

/**
 * 延迟获取元素方法，可以是 refObject，callback，query，element
 */
export type ThunkElement<T> = string | T | null | CallbackThunkElement<T> | RefThunkElement<T>;

export const getThunkElement = <T extends object>(container: ThunkElement<T>) => {
  if (!container) {
    return null;
  }
  if (isFunction(container)) {
    return container();
  }
  if (typeof container === 'string') {
    return document.querySelector<T extends Element ? T : never>(container);
  }
  if ('current' in container) {
    return container.current;
  }
  return container;
};
